import React, { useState } from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faBars, faXmark } from '@fortawesome/free-solid-svg-icons';
import './Navbar.css';
import { Link } from 'react-router-dom';
import { isMobile } from 'react-device-detect';

function Navbar() {
	const [nav, setNav] = useState(false);

	const openNav = () => {
		setNav(!nav);
	};

	return (
		<div className="navbar-section" style={{ height: isMobile ? '100px' : '240px' }}>

			<ADPLOGO />
			{/* Desktop */}
			<ul className="navbar-items" style={{ display: isMobile ? 'none' : 'flex' }}>
				<li>
					<a href="#/flowhero" className="navbar-links">
						{'FLOWHERO™'}
					</a>
				</li>
				<li>
					<a onClick={() => window.scrollTo({ top: document.body.scrollHeight, behavior: 'smooth' })} style={{ cursor: 'pointer', fontSize: '20px' }}>
						{'ABOUT'}
					</a>
				</li>
			</ul>

			{/* Mobile */}
			<div className={`mobile-navbar ${nav ? 'open-nav' : ''}`}>
				<div onClick={openNav} className="mobile-navbar-close">
					<FontAwesomeIcon icon={faXmark} className="hamb-icon" />
				</div>

				<ul className="mobile-navbar-links">
					<li>
						<Link onClick={openNav} to="/">
							{'HOME'}
						</Link>
					</li>

					<li>
						<a onClick={openNav} href="/#/flowhero">
							{'FLOWHERO™'}
						</a>
					</li>
				</ul>
			</div>

			{/* Hamburger Icon */}
			<div className="mobile-nav" style={{ display: isMobile ? 'block' : 'none' }}>
				<FontAwesomeIcon icon={faBars} onClick={openNav} className="hamb-icon" />
			</div>
		</div>
	);
}

export default Navbar;

export const ADPLOGO = () => {
	return <div style={{ display: 'flex', justifyItems: 'center', alignItems: 'center', alignContent: 'center' }}>
		{!isMobile && <div id="containerNav">
			<div id="circleNav"></div>
			<div id="small-circleNav"></div>
			<div id="smaller-circleNav"></div>
			<div id="smallest-circleNav"></div>
		</div>}

		<div className="navbar-title" style={{ marginBottom: '20px' }}>
			<Link to="/" style={{ fontSize: isMobile ? '20px' : '30px', fontWeight: 'normal', marginLeft: isMobile ? '0' : '1px' }}>{'ADPGxSOFTWARE SOLUTIONS'}</Link>
		</div>
	</div>;
}